var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"갑주의 무게가 가벼워지는구나.","JPN":"鎧の重さが軽くなっていく。","ENG":"The weight of my armor is lifting.","TWN":"盔甲變輕了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그만큼 이 세계에 타기리온의 영향이 커지고 있다는 의미일 터.","JPN":"それだけこの世界にタギリオンの影響力が大きくなっているということであろう。","ENG":"Which means that Thagirion's influence on this world is getting bigger.","TWN":"這表示塔基里翁在這個世界上的影響力越來越大。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"화근을 찾아내어… 뿌리뽑아야 한다.","JPN":"災いのもとを見つけ出し...…根絶せねばならない。","ENG":"I must find the cause, and... eradicate it.","TWN":"必須尋找禍根……連根拔除。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"뭐…? 너희 코치가 그런 요청을 했다고?","JPN":"何……？　あなたたちのコーチがそんな要請をしたって？","ENG":"What...? Your coach requested that from me?","TWN":"什麼……？是你們教練提出的要求？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"네, 당신이라면 이해해줄 거라던데요?","JPN":"はい、ルネさんなら理解してくれると言いました。","ENG":"Yes. He said you'd understand.","TWN":"對啊。她還說如果是你一定會理解。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"스완의 정식 수배는 그렇다 쳐도 관리도시 여섯 곳이 세워진 이래, 단 한 번도 최고등급 재난경보는 울린 적이 없어.","JPN":"スワンの正式な手配はわかるけど、六つの管理都市ができあがって以来、一度も最高ランクの災難警報を出したことはない。","ENG":"I understand putting an official bounty on Swan, but the highest-level disaster alert has never been triggered since the six Administration Cities were established.","TWN":"先不談史旺的正式通緝令，自從六個管理城市建立以來，從沒有發出過最高級別的災難警報。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이제야 좀 혼란이 수습되나 했는데, 지금 타이밍에 산통을 깨면 어쩌자는 거야?","JPN":"混乱からやっと落ち着いたっていうのに、それをこのタイミングで壊してどうするつもりだ？","ENG":"Just when I thought the chaos was settling down, you want me to cause more confusion?","TWN":"還以為混亂終於要平息了，結果又出事情？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>사람들에게 경각심을 주는 정도로 세계멸망을 막을 수 있다면 해볼만한 거래지 않겠나?</color>","JPN":"<color=#ffd34c>人々に警告するだけで世界の滅亡を防げるのなら、やってみる価値がある取引ではないか？</color>","ENG":"<color=#ffd34c>Won't it be worth it if you can prevent the apocalypse by bringing awareness to the people?</color>","TWN":"<color=#ffd34c>如果能透過引起人們的警戒心來避免世界末日，這難道不值得一試嗎？</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"…라고 코치가 그러던데?","JPN":"……とコーチが言っていたぞ？","ENG":"...Is what Coach said.","TWN":"教練是這麼說的。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"선택은 어디까지나 시니어인 당신의 몫으로 맡기겠다고 했어.","JPN":"選択はあくまでもシニアであるあんたに任せると言ったよ。","ENG":"He also said that it's up to you, the Senior.","TWN":"他說會把決定權留給身為Senior的你。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하, 책임은 전부 이쪽에 떠넘겨 놓고 선택하라고?","JPN":"は、責任は全部こっちに押し付けておいて、選択しろって？","ENG":"Ugh, so he wants me to take all responsibility and choose?","TWN":"哈，他是想把責任都推卸給我吧？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"말이 부탁이지 아주 자기 멋대로잖아.","JPN":"何が頼みだ、全部自分勝手じゃないか。","ENG":"Sounds more like a one-sided request if you ask me.","TWN":"這哪是請求，簡直胡來。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"최고등급 재난경보라고요?","JPN":"最高ランクの災難警報？","ENG":"The highest-level disaster alert?","TWN":"最高級別的災難警報？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그래, 상부에선 이미 결정을 마쳤다고 하더군.","JPN":"そう、上層部ではすでに決定を下したようだ。","ENG":"Yes. The higher-ups have already made their decision.","TWN":"是的，據說高層已經做好決定了。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"관리도시 여섯 곳 전체에 경보를 울릴 예정이야.","JPN":"六つの管理都市全体に警報を鳴らす予定だ。","ENG":"An alarm is going to set off at all six Administration Cities.","TWN":"他們將在全部六座管理城市發佈警報。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};